package storage

import (
	"context"
	"errors"
	"fmt"
	"io"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	"github.com/aws/aws-sdk-go-v2/service/s3/types"
)

// Config holds the S3-compatible storage configuration.
type Config struct {
	Endpoint       string
	Bucket         string
	AccessKey      string
	SecretKey      string
	Region         string
	ForcePathStyle bool
}

// Client wraps an S3 client for object storage operations.
type Client struct {
	s3Client      *s3.Client
	presignClient *s3.PresignClient
	bucket        string
}

// New creates an S3 storage client from the given config.
func New(cfg Config) (*Client, error) {
	if cfg.Bucket == "" {
		return nil, fmt.Errorf("storage: bucket name is required")
	}

	opts := []func(*awsconfig.LoadOptions) error{
		awsconfig.WithRegion(cfg.Region),
	}

	if cfg.AccessKey != "" && cfg.SecretKey != "" {
		opts = append(opts, awsconfig.WithCredentialsProvider(
			credentials.NewStaticCredentialsProvider(cfg.AccessKey, cfg.SecretKey, ""),
		))
	}

	awsCfg, err := awsconfig.LoadDefaultConfig(context.Background(), opts...)
	if err != nil {
		return nil, fmt.Errorf("storage: load aws config: %w", err)
	}

	s3Opts := []func(*s3.Options){}
	if cfg.Endpoint != "" {
		s3Opts = append(s3Opts, func(o *s3.Options) {
			o.BaseEndpoint = aws.String(cfg.Endpoint)
		})
	}
	if cfg.ForcePathStyle {
		s3Opts = append(s3Opts, func(o *s3.Options) {
			o.UsePathStyle = true
		})
	}

	client := s3.NewFromConfig(awsCfg, s3Opts...)

	return &Client{
		s3Client:      client,
		presignClient: s3.NewPresignClient(client),
		bucket:        cfg.Bucket,
	}, nil
}

// Upload uploads content to S3 at the given key.
func (c *Client) Upload(ctx context.Context, key string, body io.Reader, contentType string) error {
	input := &s3.PutObjectInput{
		Bucket:      aws.String(c.bucket),
		Key:         aws.String(key),
		Body:        body,
		ContentType: aws.String(contentType),
	}

	if _, err := c.s3Client.PutObject(ctx, input); err != nil {
		return fmt.Errorf("storage: upload %q: %w", key, err)
	}
	return nil
}

// Download retrieves content from S3 at the given key.
func (c *Client) Download(ctx context.Context, key string) (io.ReadCloser, error) {
	output, err := c.s3Client.GetObject(ctx, &s3.GetObjectInput{
		Bucket: aws.String(c.bucket),
		Key:    aws.String(key),
	})
	if err != nil {
		return nil, fmt.Errorf("storage: download %q: %w", key, err)
	}
	return output.Body, nil
}

// Delete removes an object from S3.
func (c *Client) Delete(ctx context.Context, key string) error {
	if _, err := c.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
		Bucket: aws.String(c.bucket),
		Key:    aws.String(key),
	}); err != nil {
		return fmt.Errorf("storage: delete %q: %w", key, err)
	}
	return nil
}

// Exists checks if an object exists at the given key.
func (c *Client) Exists(ctx context.Context, key string) (bool, error) {
	_, err := c.s3Client.HeadObject(ctx, &s3.HeadObjectInput{
		Bucket: aws.String(c.bucket),
		Key:    aws.String(key),
	})
	if err != nil {
		var notFound *types.NotFound
		if errors.As(err, &notFound) {
			return false, nil
		}
		return false, fmt.Errorf("storage: exists %q: %w", key, err)
	}
	return true, nil
}

// PresignedURL generates a pre-signed URL for temporary read access.
func (c *Client) PresignedURL(ctx context.Context, key string, expiry time.Duration) (string, error) {
	req, err := c.presignClient.PresignGetObject(ctx, &s3.GetObjectInput{
		Bucket: aws.String(c.bucket),
		Key:    aws.String(key),
	}, s3.WithPresignExpires(expiry))
	if err != nil {
		return "", fmt.Errorf("storage: presign %q: %w", key, err)
	}
	return req.URL, nil
}

package storage

import (
	"fmt"

	"github.com/google/uuid"
)

// KeyFor generates the S3 key for an item's content.
// Pattern: {owner_id}/{type}/{item_id}/{filename}
func KeyFor(ownerID uuid.UUID, itemType string, itemID uuid.UUID, filename string) string {
	return fmt.Sprintf("%s/%s/%s/%s", ownerID, itemType, itemID, filename)
}

// BookmarkKey returns the key for a bookmark's fetched HTML content.
func BookmarkKey(ownerID, itemID uuid.UUID) string {
	return KeyFor(ownerID, "bookmarks", itemID, "content.html")
}

// AudioKey returns the key for a voice note's audio file.
func AudioKey(ownerID, itemID uuid.UUID, format string) string {
	return KeyFor(ownerID, "voice_notes", itemID, "audio."+format)
}

// FileKey returns the key for a generic file upload.
func FileKey(ownerID, itemID uuid.UUID, filename string) string {
	return KeyFor(ownerID, "files", itemID, filename)
}

package storage

import (
	"testing"

	"github.com/google/uuid"
)

func TestKeyFor(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	tests := []struct {
		name     string
		itemType string
		filename string
		want     string
	}{
		{
			name:     "basic key",
			itemType: "bookmarks",
			filename: "content.html",
			want:     "11111111-1111-1111-1111-111111111111/bookmarks/22222222-2222-2222-2222-222222222222/content.html",
		},
		{
			name:     "nested filename",
			itemType: "files",
			filename: "document.pdf",
			want:     "11111111-1111-1111-1111-111111111111/files/22222222-2222-2222-2222-222222222222/document.pdf",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := KeyFor(ownerID, tt.itemType, itemID, tt.filename)
			if got != tt.want {
				t.Errorf("KeyFor() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestBookmarkKey(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	got := BookmarkKey(ownerID, itemID)
	want := "11111111-1111-1111-1111-111111111111/bookmarks/22222222-2222-2222-2222-222222222222/content.html"
	if got != want {
		t.Errorf("BookmarkKey() = %q, want %q", got, want)
	}
}

func TestAudioKey(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	tests := []struct {
		format string
		want   string
	}{
		{"webm", "11111111-1111-1111-1111-111111111111/voice_notes/22222222-2222-2222-2222-222222222222/audio.webm"},
		{"mp3", "11111111-1111-1111-1111-111111111111/voice_notes/22222222-2222-2222-2222-222222222222/audio.mp3"},
	}

	for _, tt := range tests {
		t.Run(tt.format, func(t *testing.T) {
			got := AudioKey(ownerID, itemID, tt.format)
			if got != tt.want {
				t.Errorf("AudioKey() = %q, want %q", got, tt.want)
			}
		})
	}
}

func TestFileKey(t *testing.T) {
	ownerID := uuid.MustParse("11111111-1111-1111-1111-111111111111")
	itemID := uuid.MustParse("22222222-2222-2222-2222-222222222222")

	got := FileKey(ownerID, itemID, "report.pdf")
	want := "11111111-1111-1111-1111-111111111111/files/22222222-2222-2222-2222-222222222222/report.pdf"
	if got != want {
		t.Errorf("FileKey() = %q, want %q", got, want)
	}
}

